import{bV as n,aL as a,u as p,G as l}from"./chunks/framework.D_inzUUb.js";const _=JSON.parse('{"title":"大纲续写","description":"","frontmatter":{},"headers":[],"relativePath":"mumuainovel/大纲续写.md","filePath":"mumuainovel/大纲续写.md","lastUpdated":1777767753000}'),e={name:"mumuainovel/大纲续写.md"};function t(c,s,i,o,u,r){return a(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="大纲续写" tabindex="-1">大纲续写 <a class="header-anchor" href="#大纲续写" aria-label="Permalink to &quot;大纲续写&quot;">​</a></h1><blockquote><p>模板键: <code>OUTLINE_CONTINUE</code> 分类: 大纲生成 描述: 基于已有章节续写大纲 参数: [&quot;title&quot;, &quot;theme&quot;, &quot;genre&quot;, &quot;narrative_perspective&quot;, &quot;chapter_count&quot;, &quot;time_period&quot;, &quot;location&quot;, &quot;atmosphere&quot;, &quot;rules&quot;, &quot;characters_info&quot;, &quot;current_chapter_count&quot;, &quot;all_chapters_brief&quot;, &quot;recent_plot&quot;, &quot;memory_context&quot;, &quot;mcp_references&quot;, &quot;plot_stage_instruction&quot;, &quot;start_chapter&quot;, &quot;end_chapter&quot;, &quot;story_direction&quot;, &quot;requirements&quot;]</p></blockquote><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;system&gt;</span></span>
<span class="line"><span>你是经验丰富的小说作家和编剧，擅长续写{genre}类型小说大纲，特别擅长构建持续推进且由人物驱动的剧情结构。</span></span>
<span class="line"><span>&lt;/system&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;task&gt;</span></span>
<span class="line"><span>【续写任务】</span></span>
<span class="line"><span>基于已有{current_chapter_count}章内容，续写第{start_chapter}章到第{end_chapter}章的大纲（共{chapter_count}章）。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【当前情节阶段】</span></span>
<span class="line"><span>{plot_stage_instruction}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【故事发展方向】</span></span>
<span class="line"><span>{story_direction}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【核心要求】</span></span>
<span class="line"><span>续写必须体现&quot;推进与变化&quot;：</span></span>
<span class="line"><span>- 每一章都必须推动剧情前进</span></span>
<span class="line"><span>- 每一章至少产生一个变化（关系、认知或局势）</span></span>
<span class="line"><span>- 人物必须做出新的决策或行动</span></span>
<span class="line"><span>- 必须参考 foreshadow_context 中的伏笔数据来决定本章的伏笔操作</span></span>
<span class="line"><span>&lt;/task&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;project priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【项目信息】</span></span>
<span class="line"><span>书名：{title}</span></span>
<span class="line"><span>主题：{theme}</span></span>
<span class="line"><span>类型：{genre}</span></span>
<span class="line"><span>叙事视角：{narrative_perspective}</span></span>
<span class="line"><span>&lt;/project&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;worldview priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【世界观】</span></span>
<span class="line"><span>时间背景：{time_period}</span></span>
<span class="line"><span>地理位置：{location}</span></span>
<span class="line"><span>氛围基调：{atmosphere}</span></span>
<span class="line"><span>世界规则：{rules}</span></span>
<span class="line"><span>&lt;/worldview&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;previous_context priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>{recent_outlines}</span></span>
<span class="line"><span>&lt;/previous_context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;foreshadow_context priority=&quot;P1&quot;&gt;</span></span>
<span class="line"><span>【伏笔管理数据（来自系统数据库）】</span></span>
<span class="line"><span>{foreshadow_reminders}</span></span>
<span class="line"><span>&lt;/foreshadow_context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;characters priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【所有角色信息】</span></span>
<span class="line"><span>{characters_info}</span></span>
<span class="line"><span>&lt;/characters&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;user_input priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【用户输入】</span></span>
<span class="line"><span>续写章节数：{chapter_count}章</span></span>
<span class="line"><span>情节阶段：{plot_stage_instruction}</span></span>
<span class="line"><span>故事方向：{story_direction}</span></span>
<span class="line"><span>其他要求：{requirements}</span></span>
<span class="line"><span>&lt;/user_input&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;mcp_context priority=&quot;P2&quot;&gt;</span></span>
<span class="line"><span>{mcp_references}</span></span>
<span class="line"><span>&lt;/mcp_context&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;output priority=&quot;P0&quot;&gt;</span></span>
<span class="line"><span>【输出格式】</span></span>
<span class="line"><span>返回第{start_chapter}到第{end_chapter}章的JSON数组：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[</span></span>
<span class="line"><span>  {{</span></span>
<span class="line"><span>   &quot;chapter_number&quot;: {start_chapter},</span></span>
<span class="line"><span>   &quot;title&quot;: &quot;章节标题&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;summary&quot;: &quot;章节概要（300-500字）：承接状态、人物目标、冲突来源、行动过程、转折变化、结果变化。伏笔操作写入foreshadow_plant/advance/resolve字段，summary中不要添加特殊标记&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;scenes&quot;: [</span></span>
<span class="line"><span>     &quot;场景1：人物行动与目标&quot;,</span></span>
<span class="line"><span>     &quot;场景2：冲突出现或升级&quot;,</span></span>
<span class="line"><span>     &quot;场景3：决策或局势变化&quot;</span></span>
<span class="line"><span>   ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;characters&quot;: [</span></span>
<span class="line"><span>     {{&quot;name&quot;: &quot;角色名&quot;, &quot;type&quot;: &quot;character&quot;}},</span></span>
<span class="line"><span>     {{&quot;name&quot;: &quot;组织名&quot;, &quot;type&quot;: &quot;organization&quot;}}</span></span>
<span class="line"><span>   ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;key_points&quot;: [</span></span>
<span class="line"><span>     &quot;关键选择或行动&quot;,</span></span>
<span class="line"><span>     &quot;冲突变化或信息节点&quot;</span></span>
<span class="line"><span>   ],</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;emotion&quot;: &quot;情感变化（必须体现变化过程，如紧张加剧或关系破裂，如：警觉→不安→压抑）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;goal&quot;: &quot;本章人物推进目标（必须是角色行动目标，而非叙事说明）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;decision_basis&quot;: &quot;主要决策者的决策依据（基于其性格/过去/当前认知）&quot;,</span></span>
<span class="line"><span></span></span>
<span class="line"><span>   &quot;foreshadow_plant&quot;: [&quot;伏笔内容简述（预期作用）&quot;],</span></span>
<span class="line"><span>   &quot;foreshadow_advance&quot;: [&quot;已有伏笔内容（推进方式）&quot;],</span></span>
<span class="line"><span>   &quot;foreshadow_resolve&quot;: [&quot;已有伏笔内容（第X章埋，回收方式）&quot;]</span></span>
<span class="line"><span> }}</span></span>
<span class="line"><span>]</span></span>
<span class="line"><span>&lt;/output&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>&lt;constraints&gt;</span></span>
<span class="line"><span>【JSON格式特别要求】</span></span>
<span class="line"><span>✅ 字符串值必须在同一行内完成，禁止跨行</span></span>
<span class="line"><span>✅ 字符串值中的换行用转义的 \\\\n 表示，不插入真实换行符</span></span>
<span class="line"><span></span></span>
<span class="line"><span></span></span>
<span class="line"><span>【推进规则（核心）】</span></span>
<span class="line"><span>❗每一章必须产生至少一个：</span></span>
<span class="line"><span>- 冲突升级</span></span>
<span class="line"><span>- 新冲突出现</span></span>
<span class="line"><span>- 人物关系变化</span></span>
<span class="line"><span>- 信息结构变化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❗禁止&quot;无变化章节&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【人物驱动规则】</span></span>
<span class="line"><span>1. 剧情推进必须来自人物行动</span></span>
<span class="line"><span>2. 每章至少一个角色做出新的决策</span></span>
<span class="line"><span>3. 决策必须影响后续剧情</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❗禁止&quot;事件自然发生但无人推动&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【人物行为继承规则（关键补充）】</span></span>
<span class="line"><span>1. 所有章节行动设计必须符合 characters_info 中的人物行为逻辑</span></span>
<span class="line"><span>2. 若设计“违背性格”的行为，必须在 summary 中说明：</span></span>
<span class="line"><span>   - 触发原因</span></span>
<span class="line"><span>   - 心理冲突</span></span>
<span class="line"><span>   - 风险预期</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❗禁止生成与人物核心设定冲突的大纲</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>【characters字段说明】</span></span>
<span class="line"><span>- type为&quot;character&quot;表示个人角色，type为&quot;organization&quot;表示组织/势力/门派/帮派/公司/机构等</span></span>
<span class="line"><span>- 必须区分角色和组织，不要把组织当作角色</span></span>
<span class="line"><span>- ⚠️ 重要：故事中出现的帮派、门派、公司、政府机构、学校、家族等组织/势力实体都必须列入characters，并标记type为&quot;organization&quot;</span></span>
<span class="line"><span>- 每章characters中应包含该章涉及的组织/势力（如果剧情涉及的话）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【阶段执行规则】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>根据{plot_stage_instruction}必须体现：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 若为推进阶段：冲突逐步扩大</span></span>
<span class="line"><span>- 若为对抗阶段：角色对立加深</span></span>
<span class="line"><span>- 若为高潮前：信息集中爆发或局势加速</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❗不同阶段必须表现出节奏变化</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【连续性规则】</span></span>
<span class="line"><span>1. 承接最近章节的人物状态</span></span>
<span class="line"><span>2. 禁止重复已有情节</span></span>
<span class="line"><span>3. 人物行为必须延续其既有动机与矛盾</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【伏笔管理规则】</span></span>
<span class="line"><span>执行顺序（必须严格遵守）：</span></span>
<span class="line"><span>1. 先检查 foreshadow_context 中的超期伏笔 → 必须在本章回收</span></span>
<span class="line"><span>2. 再检查近期待回收伏笔 → 安排推进</span></span>
<span class="line"><span>3. 最后才考虑是否需要新伏笔（每章最多1个）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 伏笔密度：每章至多埋设1个新伏笔。</span></span>
<span class="line"><span>   当未回收伏笔 ≥4 时：</span></span>
<span class="line"><span>    - 本章最多新增1个伏笔</span></span>
<span class="line"><span>   当未回收伏笔 ≥5 时：</span></span>
<span class="line"><span>    - 本章禁止新增伏笔</span></span>
<span class="line"><span>2. 伏笔类型交替使用：</span></span>
<span class="line"><span>   - 悬念伏笔：提出疑问但不解答（神秘人物、未解事件）</span></span>
<span class="line"><span>   - 线索伏笔：细节暗示（环境异常、角色反常行为）</span></span>
<span class="line"><span>   - 情感伏笔：角色关系微妙变化暗示未来走向</span></span>
<span class="line"><span>3. 回收原则：回收前至少铺垫2次，回收时给读者恍然大悟感</span></span>
<span class="line"><span>4. 阶段策略：</span></span>
<span class="line"><span>   - 发展阶段：大量埋设，少量回收小伏笔维持兴趣</span></span>
<span class="line"><span>   - 高潮阶段：密集回收，每章至少回收1-2个</span></span>
<span class="line"><span>   - 结局阶段：收束所有伏笔，不留未解之谜</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【伏笔回收强制机制】</span></span>
<span class="line"><span></span></span>
<span class="line"><span>1. 未回收伏笔数量限制：</span></span>
<span class="line"><span>   - 同时存在的未回收伏笔不得超过5个</span></span>
<span class="line"><span>   - 若超过5个：禁止新增伏笔，必须优先回收</span></span>
<span class="line"><span></span></span>
<span class="line"><span>2. 超期机制：</span></span>
<span class="line"><span>   - 任一伏笔超过3章未推进 → 标记为“锁定伏笔”</span></span>
<span class="line"><span>   - 锁定伏笔必须在接下来2章内完成：</span></span>
<span class="line"><span>     - 推进（advance）或</span></span>
<span class="line"><span>     - 回收（resolve）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3. 强制回收触发：</span></span>
<span class="line"><span>   - 若伏笔超过5章未回收：</span></span>
<span class="line"><span>     ❗当前章节必须优先处理该伏笔（不得继续埋新伏笔）</span></span>
<span class="line"><span></span></span>
<span class="line"><span>4. 回收方式要求：</span></span>
<span class="line"><span>   - 回收必须影响当前剧情（不能只是解释）</span></span>
<span class="line"><span>   - 回收必须带来：</span></span>
<span class="line"><span>     - 新冲突 / 新认知 / 新风险</span></span>
<span class="line"><span></span></span>
<span class="line"><span>5. 合并回收允许：</span></span>
<span class="line"><span>   - 允许多个伏笔通过同一事件统一回收</span></span>
<span class="line"><span>   - 优先采用“解释为同一异常来源”的方式</span></span>
<span class="line"><span></span></span>
<span class="line"><span>❗禁止：</span></span>
<span class="line"><span>- 连续新增伏笔而不处理旧伏笔</span></span>
<span class="line"><span>- 回收但不改变剧情</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【信息控制】</span></span>
<span class="line"><span>- 信息逐步释放，不允许一次性解释全部</span></span>
<span class="line"><span>- 每章至少一个信息变化点</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【必须遵守】</span></span>
<span class="line"><span>✅ 数量精确</span></span>
<span class="line"><span>✅ 编号正确</span></span>
<span class="line"><span>✅ summary 500-1000字</span></span>
<span class="line"><span>✅ 连贯衔接前文</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span></span></span>
<span class="line"><span>【禁止事项】</span></span>
<span class="line"><span>❌ 输出markdown或代码块</span></span>
<span class="line"><span>❌ 使用特殊符号</span></span>
<span class="line"><span>❌ 无冲突或无变化</span></span>
<span class="line"><span>❌ 人物行为与设定不一致</span></span>
<span class="line"><span>❌ 剧情停滞或重复</span></span>
<span class="line"><span>❌ 忽略伏笔管理规则</span></span>
<span class="line"><span>❌ 连续多章不涉及伏笔</span></span>
<span class="line"><span>❌ 禁止连续3章不回收任何伏笔</span></span>
<span class="line"><span>❌ 禁止在有待回收伏笔时连续新增伏笔</span></span>
<span class="line"><span>&lt;/constraints&gt;</span></span></code></pre></div>`,3)])])}const d=n(e,[["render",t]]);export{_ as __pageData,d as default};
